import json

NEW_INTRO = {
"158": "Основные понятия: Биоэлектрогенез — это совокупность процессов возникновения и поддержания электрических потенциалов на биологических мембранах живых клеток, лежащая в основе работы нервной системы, мышц и многих других тканей организма. Источниками биоэлектрических сигналов служат неравномерное (асимметричное) распределение различных ионов (в первую очередь калия, натрия, хлора, кальция) между внутри- и внеклеточной средой, а также избирательная проницаемость клеточной мембраны для разных ионов, обеспечиваемая работой ионных каналов и ионных насосов. Именно разность концентраций ионов по обе стороны мембраны в сочетании с избирательной проницаемостью мембраны и создаёт трансмембранную разность потенциалов, которая может изменяться и распространяться, обеспечивая передачу сигналов в организме.",
"159": "Основные понятия: Потенциал покоя — это относительно стабильная разность электрических потенциалов между внутренней и наружной сторонами клеточной мембраны невозбуждённой (находящейся в состоянии покоя) клетки, при которой внутренняя сторона мембраны заряжена отрицательно относительно наружной. Возникновение трансмембранной разности потенциалов требует одновременного выполнения двух условий: неравномерного распределения ионов между цитоплазмой и внеклеточной средой (создаваемого, в частности, работой натрий-калиевого насоса) и избирательной (различной для разных ионов) проницаемости мембраны в состоянии покоя, которая в норме значительно выше для ионов калия, чем для ионов натрия — поэтому потенциал покоя близок к равновесному потенциалу именно для калия. Потенциал покоя — не статичное, а динамически поддерживаемое состояние, требующее постоянных энергетических затрат клетки на работу ионных насосов.",
"160": "Основные понятия: Формула Нернста рассчитывает равновесный потенциал для отдельно взятого вида ионов — то есть такую разность потенциалов на мембране, при которой электрическая сила, действующая на данный ион, в точности уравновешивает диффузионную силу, вызванную разностью концентраций этого иона по обе стороны мембраны, так что суммарный поток данного иона через мембрану становится равным нулю. Равновесный потенциал по формуле Нернста зависит от отношения концентраций иона снаружи и внутри клетки, от заряда иона и от температуры — чем больше разница концентраций, тем больше по модулю равновесный потенциал для данного иона. Формула Нернста — идеализированный случай, справедливый только тогда, когда мембрана проницаема для одного-единственного вида ионов; в реальности мембрана проницаема сразу для нескольких ионов, поэтому фактический мембранный потенциал рассчитывается более сложным уравнением Гольдмана.",
"161": "Основные понятия: Уравнение Гольдмана — это более общая и реалистичная (по сравнению с формулой Нернста) модель расчёта мембранного потенциала, учитывающая одновременный вклад нескольких видов ионов (обычно калия, натрия и хлора), которые могут проникать через мембрану клетки, каждый со своей собственной проницаемостью и концентрационным градиентом. Итоговый мембранный потенциал по уравнению Гольдмана представляет собой своего рода «средневзвешенное» значение равновесных потенциалов отдельных ионов, где вес каждого иона в этом «взвешивании» определяется его относительной проницаемостью через мембрану в данный момент — ион с наибольшей проницаемостью вносит наибольший вклад в итоговый потенциал. Именно уравнение Гольдмана объясняет, почему потенциал покоя близок (но не в точности равен) равновесному калиевому потенциалу, а при возбуждении клетки, когда резко возрастает натриевая проницаемость, мембранный потенциал резко смещается в сторону равновесного натриевого потенциала.",
"162": "Основные понятия: Модель Ходжкина-Хаксли — это количественная математическая модель, описывающая механизм возникновения и распространения потенциала действия нервного волокна через динамику изменения проницаемости (проводимости) мембраны для ионов натрия и калия в зависимости от величины мембранного потенциала и времени. Ключевая идея модели в том, что натриевая и калиевая проводимости мембраны управляются потенциал-зависимыми ионными каналами, которые открываются и закрываются по определённым, экспериментально измеренным законам в ответ на изменение мембранного потенциала, создавая последовательность быстрого входящего натриевого тока (деполяризация) и запаздывающего выходящего калиевого тока (реполяризация). Модель Ходжкина-Хаксли — одно из важнейших достижений биофизики XX века, впервые количественно и предсказательно объяснившее электрическую возбудимость нервных клеток на основе ионных механизмов.",
"163": "Основные понятия: Пассивный транспорт веществ через клеточную мембрану происходит самопроизвольно, по градиенту концентрации (из области высокой концентрации в область низкой) или по электрохимическому градиенту, без затраты клеткой метаболической энергии — к нему относятся простая диффузия через липидный бислой и облегчённая диффузия через ионные каналы или белки-переносчики. Активный транспорт, напротив, переносит вещества против их концентрационного (или электрохимического) градиента, что термодинамически невыгодно и требует обязательной затраты энергии клеткой (обычно за счёт гидролиза АТФ, как в работе натрий-калиевого насоса), — именно активный транспорт создаёт и поддерживает те неравномерные концентрационные градиенты ионов, за счёт которых затем возможен пассивный ионный ток при возбуждении клетки. Баланс активного и пассивного транспорта — основа поддержания постоянства внутренней среды клетки (гомеостаза) и её электрической возбудимости.",
"164": "Основные понятия: Потенциал действия — это быстрое, кратковременное и значительное по амплитуде изменение мембранного потенциала возбудимой клетки (нейрона, мышечного волокна), возникающее в ответ на достаточно сильное раздражение и служащее универсальным электрическим сигналом для передачи информации в нервной и мышечной ткани. Ключевые свойства потенциала действия: он возникает по закону «всё или ничего» (либо не возникает вовсе, либо развивается с максимальной, характерной для данной клетки амплитудой, независимо от силы надпорогового раздражителя), распространяется по мембране без затухания (в отличие от пассивно распространяющихся, затухающих сигналов) и сопровождается кратковременным периодом невозбудимости (рефрактерностью), что обеспечивает однонаправленность его распространения. Именно эти свойства позволяют потенциалу действия надёжно передавать сигнал на значительные расстояния без потери информации.",
"165": "Основные понятия: Потенциал действия развивается через последовательность фаз, каждой из которых соответствует определённое состояние ионных каналов мембраны и направление ионных токов: фаза деполяризации (быстрое открытие потенциал-зависимых натриевых каналов и мощный входящий поток ионов натрия, резко смещающий мембранный потенциал в положительную сторону), фаза реполяризации (инактивация натриевых каналов и отсроченное открытие калиевых каналов, приводящее к выходящему потоку ионов калия и возвращению потенциала к отрицательным значениям), и часто следующая за ней фаза следовой гиперполяризации (потенциал временно становится даже более отрицательным, чем исходный потенциал покоя, из-за сохраняющейся повышенной калиевой проводимости). Последовательное и строго координированное открытие и закрытие разных типов ионных каналов на разных фазах и обеспечивает характерную, воспроизводимую форму потенциала действия.",
"166": "Основные понятия: Биологическая мембрана — это тонкая (толщиной несколько нанометров) структура, окружающая клетку и её внутренние органеллы, основу которой составляет двойной слой (бислой) фосфолипидных молекул с встроенными в него белками (каналами, насосами, рецепторами, ферментами). Мембрана выполняет несколько важнейших функций: барьерную (отделяет внутреннее содержимое клетки от внешней среды, препятствуя свободному прохождению большинства веществ), транспортную (избирательно регулирует прохождение ионов и молекул через специализированные белковые структуры), рецепторную (воспринимает сигналы из внешней среды через мембранные рецепторы) и электрогенную (обеспечивает поддержание трансмембранной разности потенциалов). Именно избирательная проницаемость мембраны для разных ионов, обеспечиваемая её белковым составом, лежит в основе всех биоэлектрических явлений клетки.",
"167": "Основные понятия: Ионные каналы — это специализированные белковые структуры, встроенные в клеточную мембрану и образующие в ней узкий, избирательный (селективный) проход, через который определённые ионы (натрия, калия, кальция, хлора) могут проходить по градиенту концентрации значительно быстрее и эффективнее, чем путём простой диффузии через липидный бислой. По механизму открытия (активации) ионные каналы делятся на несколько типов: потенциал-зависимые (открываются в ответ на изменение мембранного потенциала — ключевые для генерации потенциала действия), лиганд-зависимые (открываются при связывании определённой молекулы-лиганда, например нейромедиатора — ключевые для синаптической передачи) и механочувствительные (открываются в ответ на механическую деформацию мембраны). Разнообразие типов и селективности ионных каналов обеспечивает клеткам огромную гибкость в регуляции своей электрической активности и реакции на различные сигналы.",
"168": "Основные понятия: Модели ионных каналов описывают их работу как молекулярных «ворот», которые могут находиться в одном из нескольких состояний — закрытом (канал непроницаем для ионов), открытом (канал проницаем, ионы движутся через него по градиенту) и инактивированном (канал временно неспособен открыться, даже если стимул для его активации присутствует, что важно для обеспечения рефрактерности). Основные свойства ионных каналов включают ионную селективность (способность пропускать преимущественно один определённый вид ионов, а не любые ионы подряд), потенциал- или лиганд-зависимость (переход между состояниями регулируется электрическим или химическим сигналом) и способность к быстрой, воспроизводимой кинетике переключения между состояниями, что обеспечивает быстроту и надёжность электрических сигналов в возбудимых тканях.",
"169": "Основные понятия: Возбудимость — это общее свойство некоторых видов клеток (нервных, мышечных, железистых) отвечать на действие раздражителя специфической быстрой реакцией — генерацией потенциала действия; возбуждение — это сам процесс перехода клетки из состояния покоя в активное, деятельное состояние в ответ на раздражитель, сопровождающийся характерными изменениями мембранного потенциала и физиологической активности клетки. Критический уровень деполяризации (пороговый потенциал) — это такое значение мембранного потенциала, при достижении которого входящий натриевый ток становится больше уравновешивающего его выходящего тока, процесс деполяризации приобретает лавинообразный, самоподдерживающийся характер, и возникает полноценный потенциал действия; при деполяризации, не достигшей этого критического уровня, изменение потенциала носит лишь локальный, затухающий (не распространяющийся) характер.",
"170": "Основные понятия: Пороговый раздражитель — это минимальная по силе величина раздражения, которая ещё способна вызвать возникновение потенциала действия (довести деполяризацию мембраны до критического уровня); раздражители меньшей силы (подпороговые) вызывают лишь локальные, нераспространяющиеся изменения потенциала, которые затухают, не успев запустить полноценное возбуждение. Закон «всё или ничего» гласит, что при достижении порогового уровня раздражения возникающий потенциал действия развивается с максимальной, характерной для данной клетки амплитудой независимо от того, насколько сильнее порогового был использованный стимул — дальнейшее увеличение силы раздражителя выше порога не увеличивает амплитуду отдельного потенциала действия. Этот закон объясняет, каким образом нервная система кодирует информацию о силе раздражителя не изменением амплитуды отдельных импульсов, а изменением частоты их следования.",
"171": "Основные понятия: Рефрактерность — это временное снижение (или полное отсутствие) возбудимости клетки сразу после генерации потенциала действия, обусловленное особым (инактивированным) состоянием натриевых каналов, которые не могут повторно открыться до тех пор, пока мембранный потенциал не вернётся к достаточно отрицательным значениям. Различают абсолютную рефрактерность (короткий период сразу после возбуждения, в течение которого клетка вообще не способна генерировать новый потенциал действия, каким бы сильным ни было раздражение) и относительную рефрактерность (следующий за ней период, когда клетка постепенно восстанавливает возбудимость и способна ответить новым потенциалом действия, но только на раздражитель повышенной силы). Рефрактерность обеспечивает однонаправленность распространения возбуждения по нервному волокну (не даёт импульсу «развернуться назад») и ограничивает максимально возможную частоту генерации импульсов клеткой.",
"172": "Основные понятия: Распространение возбуждения по возбудимой мембране (нервному волокну) происходит благодаря тому, что деполяризация в уже возбуждённом участке мембраны создаёт локальные электрические токи, которые деполяризуют соседний, ещё невозбуждённый участок мембраны до критического (порогового) уровня, вызывая в нём новый, полноценный потенциал действия — этот процесс последовательно повторяется вдоль всего волокна. Важная особенность такого распространения в том, что потенциал действия не «затухает» по мере распространения (в отличие от пассивного распространения электрического сигнала), поскольку в каждой новой точке волокна он генерируется заново, с полной, характерной амплитудой, за счёт локальных ионных токов через мембрану данного участка, а не переносится как «готовый» электрический импульс от предыдущего участка. Однонаправленность распространения обеспечивается рефрактерностью только что возбуждённого («пройденного») участка мембраны.",
"173": "Основные понятия: Постоянная длины — это параметр, характеризующий, на каком расстоянии вдоль нервного волокна пассивно (без активной регенерации, за счёт простого затухающего распространения электрического сигнала по кабельным свойствам мембраны) распространяющийся электрический потенциал ослабевает в определённое число раз (характерное для экспоненциального затухания). Постоянная длины зависит от электрических свойств самого волокна — сопротивления мембраны (чем оно выше, тем меньше ток «утекает» через мембрану и тем на большее расстояние распространяется пассивный сигнал) и сопротивления внутриклеточной среды (аксоплазмы). Чем больше постоянная длины волокна, тем на большее расстояние подпороговый (локальный) сигнал успевает пассивно распространиться и деполяризовать соседние участки мембраны до порогового уровня, что напрямую влияет на скорость и эффективность распространения возбуждения по волокну.",
"174": "Основные понятия: Скорость распространения возбуждения (потенциала действия) по нервному волокну — это расстояние, которое проходит нервный импульс вдоль волокна за единицу времени; эта скорость определяется сочетанием кабельных (пассивных электрических) свойств волокна и активных свойств возбудимой мембраны, обеспечивающих регенерацию потенциала действия в каждой новой точке. Скорость проведения возбуждения увеличивается с ростом диаметра волокна (поскольку увеличивается постоянная длины, то есть сигнал пассивно распространяется на большее расстояние прежде чем затухнет) и особенно резко возрастает при наличии миелиновой оболочки, которая существенно повышает сопротивление мембраны и уменьшает её ёмкость, ускоряя пассивное распространение сигнала между отдельными участками возбуждения. Скорость проведения возбуждения — важный клинически значимый параметр, изменения которого используются, в частности, для диагностики повреждений периферических нервов.",
"175": "Основные понятия: Сальтаторное («скачкообразное») проведение возбуждения характерно для миелинизированных нервных волокон, у которых миелиновая оболочка (образованная шванновскими клетками или олигодендроцитами) прерывисто покрывает волокно, оставляя открытыми лишь узкие немиелинизированные участки — перехваты Ранвье, где сосредоточена высокая плотность потенциал-зависимых натриевых каналов. Благодаря высокому электрическому сопротивлению миелиновой оболочки электрический ток между соседними перехватами Ранвье распространяется пассивно, почти без потерь, практически «перескакивая» через миелинизированные участки, и активная регенерация потенциала действия (с затратой энергии на работу ионных каналов) происходит только в самих перехватах Ранвье. Такой механизм значительно (в разы) увеличивает скорость проведения возбуждения по сравнению с непрерывным проведением по немиелинизированному волокну того же диаметра, при этом требуя существенно меньших энергетических затрат клетки на восстановление ионных градиентов.",
"176": "Основные понятия: Синаптическая передача — это процесс передачи возбуждения (или торможения) от одной возбудимой клетки к другой через специализированную структуру контакта между ними — синапс, обеспечивающий одностороннюю (от пресинаптической клетки к постсинаптической) передачу сигнала. В зависимости от механизма передачи сигнала синапсы делятся на два принципиально разных типа: электрические (сигнал передаётся напрямую электрическим током через специальные межклеточные каналы, без задержки) и химические (сигнал передаётся посредством выделения и связывания химического вещества-посредника — нейромедиатора, с характерной небольшой синаптической задержкой). Синаптическая передача — ключевой механизм, обеспечивающий интеграцию и обработку информации в нервной системе, поскольку именно на уровне синапсов происходит суммация, усиление, ослабление или модуляция передаваемых сигналов.",
"177": "Основные понятия: Электрические синапсы — это тип межклеточного контакта, в котором электрический сигнал передаётся напрямую от одной клетки к другой через специальные белковые каналы (щелевые контакты, коннексоны), физически соединяющие цитоплазму соседних клеток и позволяющие ионному току проходить непосредственно из одной клетки в другую без промежуточного химического посредника. Ключевые особенности электрических синапсов — практически мгновенная передача сигнала (без синаптической задержки, характерной для химических синапсов) и, как правило, двунаправленность передачи (сигнал может распространяться в обе стороны через контакт). Электрические синапсы обеспечивают быструю и синхронную активацию групп связанных клеток и особенно важны там, где критична высокая скорость и синхронность реакции (например, в некоторых защитных рефлексах и для синхронизации сокращения клеток сердечной мышцы).",
"178": "Основные понятия: Химические синапсы — это наиболее распространённый в нервной системе тип межклеточного контакта, в котором сигнал передаётся не напрямую электрически, а опосредованно, через выделение пресинаптической клеткой химического вещества-посредника (нейромедиатора) в узкую щель между клетками (синаптическую щель), которое затем связывается со специфическими рецепторами на мембране постсинаптической клетки, вызывая в ней изменение проницаемости для определённых ионов. Такой механизм передачи, в отличие от электрических синапсов, сопряжён с небольшой временной задержкой (синаптической задержкой), необходимой на выделение, диффузию и связывание нейромедиатора, но зато обеспечивает значительно большую гибкость передачи сигнала — возможность как возбуждающего, так и тормозного действия, усиления или ослабления сигнала, а также долговременных изменений эффективности передачи (что лежит в основе процессов обучения и памяти).",
"179": "Основные понятия: Передача сигнала в химическом синапсе происходит через строго последовательные этапы: приход потенциала действия к пресинаптическому окончанию → открытие потенциал-зависимых кальциевых каналов и вход ионов кальция внутрь окончания → выброс (экзоцитоз) молекул нейромедиатора из синаптических пузырьков в синаптическую щель → диффузия нейромедиатора через щель и его связывание со специфическими рецепторами на постсинаптической мембране → открытие (или закрытие) ионных каналов постсинаптической мембраны и возникновение постсинаптического потенциала (возбуждающего или тормозного) → удаление нейромедиатора из синаптической щели (обратный захват, ферментативное разрушение или диффузия) для прекращения его действия и подготовки синапса к следующему сигналу. Именно многоступенчатость и химическая природа этого процесса делают химический синапс удобной мишенью для регуляции (в том числе фармакологической) передачи нервных сигналов.",
"180": "Основные понятия: Миокард — сердечная мышца, обладающая рядом структурных и функциональных особенностей, отличающих его от скелетной и гладкой мускулатуры: клетки миокарда (кардиомиоциты) соединены друг с другом особыми контактами — вставочными дисками, содержащими в том числе электрические синапсы (щелевые контакты), которые обеспечивают быстрое прямое распространение возбуждения от клетки к клетке. Благодаря такому строению весь миокард функционирует как функциональный синцитий — единая, электрически связанная система, в которой возбуждение, возникнув в одной точке, быстро охватывает всю мышечную массу, обеспечивая практически одновременное (координированное) сокращение всех кардиомиоцитов, необходимое для эффективного насосного действия сердца.",
"181": "Основные понятия: Возбуждение по миокарду распространяется через специализированную проводящую систему сердца, состоящую из атипичных, слабо сократимых, но обладающих способностью к автоматической (спонтанной, без внешнего стимула) генерации возбуждения кардиомиоцитов: синоатриальный (синусовый) узел — главный «водитель ритма» сердца, задающий частоту сердечных сокращений в норме, атриовентрикулярный узел, пучок Гиса и волокна Пуркинье, последовательно проводящие возбуждение от предсердий к желудочкам. Такая организация проводящей системы обеспечивает строго определённую последовательность и синхронность возбуждения разных отделов сердца — сначала сокращаются предсердия, затем (с небольшой физиологической задержкой в атриовентрикулярном узле, необходимой для эффективного заполнения желудочков кровью) сокращаются желудочки, что критически важно для эффективной насосной функции сердца.",
"182": "Основные понятия: Электрокардиограмма (ЭКГ) — это регистрируемая с поверхности тела запись суммарной электрической активности сердца, отражающая процессы возбуждения (деполяризации) и восстановления (реполяризации), последовательно происходящие в разных отделах сердца в течение сердечного цикла. Типичная ЭКГ состоит из характерных зубцов и интервалов, каждый из которых отражает определённый этап распространения возбуждения по сердцу: зубец P соответствует возбуждению предсердий, комплекс QRS — быстрому возбуждению (деполяризации) желудочков, а зубец T — восстановлению (реполяризации) желудочков после сокращения. Анализ формы, амплитуды и временных интервалов между этими элементами ЭКГ позволяет врачу оценивать ритм, проводимость и общее состояние электрической активности сердца, выявляя нарушения ритма, проводимости и признаки повреждения сердечной мышцы.",
"183": "Основные понятия: Сенсорная система (анализатор) — это совокупность нервных структур, обеспечивающая восприятие определённого вида раздражителей из внешней или внутренней среды организма и преобразование их в осознаваемое ощущение; общее строение любой сенсорной системы включает три последовательных звена: периферический отдел (рецепторы, специализированные на восприятии конкретного вида энергии раздражителя и преобразовании её в электрический сигнал — процесс рецепции и трансдукции), проводниковый отдел (нервные пути, передающие сигнал от рецепторов к центральной нервной системе) и центральный (корковый) отдел (участок коры головного мозга, где происходит окончательный анализ и осознание поступившей сенсорной информации). Такая трёхзвенная организация характерна для всех видов сенсорных систем — зрительной, слуховой, обонятельной, вкусовой, тактильной и других, несмотря на разную физическую природу воспринимаемых ими раздражителей.",
"184": "Основные понятия: Разные виды сенсорных систем специализированы на восприятии разных по физической природе раздражителей (световых волн для зрения, звуковых волн для слуха, химических веществ для вкуса и обоняния, механических деформаций для осязания), но при этом обладают рядом общих физиологических свойств: адаптация (постепенное снижение чувствительности рецепторов при длительном действии постоянного раздражителя), наличие абсолютного порога чувствительности (минимальной интенсивности раздражителя, вызывающей ощущение) и дифференциального порога (минимального различимого изменения интенсивности раздражителя), а также определённый диапазон воспринимаемых интенсивностей и частот, за пределами которого раздражитель либо не воспринимается вовсе, либо воспринимается как боль или дискомфорт. Общность этих физиологических свойств отражает единые физические и нейрофизиологические принципы кодирования и обработки сенсорной информации в организме, несмотря на разнообразие конкретных сенсорных модальностей.",
"185": "Основные понятия: Слуховой анализатор обеспечивает восприятие звуковых (механических) колебаний и преобразование их в нервный сигнал через последовательность структур: наружное ухо (собирает и направляет звуковые волны), среднее ухо с барабанной перепонкой и цепью слуховых косточек (преобразует и усиливает механические колебания, согласуя воздушную и жидкостную среды внутреннего уха), внутреннее ухо с улиткой, где расположен кортиев орган с волосковыми клетками-рецепторами, преобразующими механические колебания жидкости улитки в электрические нервные сигналы. Особенность механизма слухового восприятия в том, что разные участки улитки (базилярной мембраны) резонансно настроены на разные частоты звука, за счёт чего происходит частотный анализ (разложение) сложного звука ещё на уровне периферического рецепторного аппарата, прежде чем сигнал достигает слуховой коры головного мозга для дальнейшей обработки.",
"186": "Основные понятия: Зрительный анализатор обеспечивает восприятие электромагнитного излучения видимого диапазона и его преобразование в зрительные образы через последовательность структур: оптическая система глаза (роговица, хрусталик), фокусирующая изображение на сетчатке, сетчатка с фоторецепторами (палочками, отвечающими за чёрно-белое сумеречное зрение при низкой освещённости, и колбочками, отвечающими за цветное зрение при дневном освещении), зрительный нерв, передающий закодированный сигнал далее по зрительным путям (через хиазму и латеральное коленчатое тело) к зрительной коре головного мозга, где происходит окончательный анализ и формирование зрительного образа. Ключевая физическая особенность зрительной рецепции — фотохимический механизм: фоторецепторы содержат светочувствительные пигменты, молекулы которых меняют свою пространственную структуру при поглощении кванта света, запуская каскад биохимических реакций, преобразующих энергию поглощённого фотона в электрический нервный сигнал.",
}

with open("physics_questions.json", "r", encoding="utf-8") as f:
    data = json.load(f)

changed = 0
for k, new_intro in NEW_INTRO.items():
    a = data[k]["answer"]
    parts = a.split("\n\n", 1)
    rest = parts[1] if len(parts) > 1 else ""
    if rest:
        data[k]["answer"] = new_intro + "\n\n" + rest
    else:
        data[k]["answer"] = new_intro
    changed += 1

with open("physics_questions.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("changed:", changed)
